const event = $json.body?.events?.[0] ?? $json.events?.[0] ?? {};

const isTextMessage =
  event.type === 'message' &&
  event.message?.type === 'text';

const text = isTextMessage ? (event.message.text ?? '').trim() : '';

return [
  {
    json: {
      eventType: event.type ?? '',
      messageType: event.message?.type ?? '',
      isTextMessage,

      userId: event.source?.userId ?? '',
      replyToken: event.replyToken ?? '',

      text,
      textNormalized: text.toLowerCase(),

      quoteToken: event.message?.quoteToken ?? '',

      timestamp: event.timestamp ?? Date.now()
    }
  }
];

return [
  {
    json: {
      userId: $json.userId,
      currentMenu: 'track_ticket',
      currentStep: 'ask_ticket_id',
      status: 'active',
      payloadJson: JSON.stringify({}),
      lastUserText: $input.first().json.text,
      updatedAt: new Date().toISOString(),
      expireAt: new Date(Date.now() + 5 * 60 * 1000).toISOString(),
      replyToken: $json.replyToken,
      quoteToken: $json.quoteToken
    }
  }
];

const ticketId = ($json.ticketId || '').trim();

// ปรับ regex ให้ตรงกับระบบจริงของคุณ
const isTicketFormatOk = /^[0-9]+$/.test(ticketId);

return [
  {
    json: {
      ...$json,
      isTicketFormatOk
    }
  }
];

function cleanDescription(html) {
  if (!html) return '';

  return html
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<div[^>]*>/gi, '')
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\n\s*\n+/g, '\n')
    .trim();
}

return items.map(item => {
  return {
    json: {
      ...item.json,
      description_clean: cleanDescription($input.first().json.request.description)
    }
  };
});

const payload = JSON.parse($json.payloadJson || '{}');

payload.reporterName = $json.text;

return [
  {
    json: {
      ...$json,
      payloadJson: JSON.stringify(payload),
      currentStep: 'ask_subject',
      lastUserText: $json.text,
      updatedAt: new Date().toISOString()
    }
  }
];

const payload = JSON.parse($json.payloadJson || '{}');

payload.subject = $json.text;

return [
  {
    json: {
      ...$json,
      payloadJson: JSON.stringify(payload),
      currentStep: 'ask_detail',
      lastUserText: $json.text,
      updatedAt: new Date().toISOString()
    }
  }
];

const payload = JSON.parse($json.payloadJson || '{}');

payload.detail = $json.text;

return [
  {
    json: {
      ...$json,
      payloadJson: JSON.stringify(payload),
      currentStep: 'confirm_submit',
      lastUserText: $json.text,
      updatedAt: new Date().toISOString(),
      reporterName: payload.reporterName || '',
      subject: payload.subject || '',
      detail: payload.detail || ''
    }
  }
];

